class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> gcds(n, 0);
        gcds[0] = nums[0];
        for (int i = 1; i < n; i++) {
            gcds[i] = __gcd(gcds[i-1], nums[i]);
        }
        long long res = 0;
        for (int i = 0; i < n; i++) {
            long long cur = 0;
            for (int j = i; j < n; j++) {
                cur = max(cur, (j - i + 1) * gcds[j]);
                if (k > 0) {
                    cur = max(cur, (j - i + 1) * __gcd(gcds[i-1], nums[j] * 2));
                    k--;
                }
            }
            res = max(res, cur);
        }
        return res;
    }
};
